mapper.select:

select * from hc_doc_bill_ref
where tenant_id = #{scopedTenantId}
  and tgt_bill_id = #{tgtBillId}
  and (del_flag = 0 or del_flag is null)
order by IFNULL(line_no, 999999) asc, create_time asc

select src_entry_id as srcEntryId, IFNULL(SUM(ref_qty), 0) as usedQty
from hc_doc_bill_ref
where tenant_id = #{tenantId}
  and src_bill_id = #{srcBillId}
  and (del_flag = 0 or del_flag is null)
group by src_entry_id

select IFNULL(SUM(ref_qty), 0)
from hc_doc_bill_ref
where tenant_id = #{tenantId}
  and src_bill_id = #{srcBillId}
  and src_entry_id = #{srcEntryId}
  and (del_flag = 0 or del_flag is null)

  and ref_type = #{refType}


  and (tgt_bill_id is null or tgt_bill_id != #{excludeTgtBillId})

select src_entry_id as srcEntryId, ifnull(sum(ref_qty), 0) as usedQty
from hc_doc_bill_ref
where tenant_id = #{tenantId}
  and src_bill_id = #{srcBillId}
  and ref_type = #{refType}
  and (del_flag = 0 or del_flag is null)
group by src_entry_id
